from flask import Flask, request, jsonify
import logging
import datetime
import os

app = Flask(__name__)

# Create logger
logger = logging.getLogger('auth_logger')
logger.setLevel(logging.INFO)

# Create file handler and set level to INFO
file_handler = logging.FileHandler('application.log')
file_handler.setLevel(logging.INFO)

# Create formatter and attach it to the file handler
formatter = logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s')
file_handler.setFormatter(formatter)

# Add the file handler to the logger
logger.addHandler(file_handler)

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    email = data.get('email')

    # Log login attempt
    logger.info(f'Login Attempt: Username={username}, Password={password}, Email={email}, IP={request.remote_addr}, User-Agent={request.user_agent.string}')

    # Authentication logic here (e.g. check against database)
    if username == 'admin' and password == 'password':
        return jsonify({'message': 'Logged in successfully'}), 200
    else:
        return jsonify({'message': 'Invalid credentials'}), 401

if __name__ == '__main__':
    app.run(debug=True)